import axios from 'axios';

const BASE_URLS = [
  'http://localhost:8080/api/librarian',
  'http://localhost:8080/librarian',
];

async function requestWithFallback(buildRequest) {
  let lastError;
  for (const baseUrl of BASE_URLS) {
    try {
      const response = await buildRequest(baseUrl);
      return response.data;
    } catch (err) {
      lastError = err;
    }
  }
  throw lastError;
}

export const librarianService = {
  getAll: () => requestWithFallback((baseUrl) => axios.get(baseUrl)),
  getById: (id) => requestWithFallback((baseUrl) => axios.get(`${baseUrl}/${id}`)),
  create: (librarian) => requestWithFallback((baseUrl) => axios.post(baseUrl, librarian)),
  update: (id, librarian) => requestWithFallback((baseUrl) => axios.put(`${baseUrl}/${id}`, librarian)),
  delete: (id) => requestWithFallback((baseUrl) => axios.delete(`${baseUrl}/${id}`)),
  searchByEmail: (email) =>
    requestWithFallback((baseUrl) => axios.get(`${baseUrl}/search/email?email=${encodeURIComponent(email)}`)),
  login: async (email, password) => {
    const attempts = [
      (baseUrl) => axios.post(`${baseUrl}/login`, { email, password }),
      (baseUrl) => axios.post('http://localhost:8080/api/librarians/login', { email, password }),
      (baseUrl) => axios.post('http://localhost:8080/librarians/login', { email, password }),
    ];

    let lastError;
    for (const attempt of attempts) {
      try {
        const response = await requestWithFallback((baseUrl) => attempt(baseUrl));
        return response;
      } catch (err) {
        lastError = err;
      }
    }

    throw lastError;
  },
};
